def get_db():
    db = SessionLocal()
    try:
        yield db          # db is injected into the handler
    finally:
        db.close()        # Always runs, even if the handler raises an exception

def get_db_transaction():
    db = SessionLocal()
    try:
        yield db
        db.commit()       # Commit if no exception
    except Exception:
        db.rollback()     # Rollback on any exception
        raise
    finally:
        db.close()        # Always close

from fastapi import Depends, HTTPException, status
from fastapi.security import OAuth2PasswordBearer
from jose import JWTError, jwt
from pydantic import BaseModel

SECRET_KEY = "..."
ALGORITHM = "HS256"

oauth2_scheme = OAuth2PasswordBearer(tokenUrl="/auth/token")

class TokenPayload(BaseModel):
    sub: int        # user ID
    exp: int        # expiry timestamp
    scopes: list[str] = []

def get_token_payload(token: str = Depends(oauth2_scheme)) -> TokenPayload:
    credentials_exception = HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail="Could not validate credentials",
        headers={"WWW-Authenticate": "Bearer"},
    )
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return TokenPayload(**payload)
    except JWTError:
        raise credentials_exception

def get_current_user(
    payload: TokenPayload = Depends(get_token_payload),
    db: Session = Depends(get_db)
) -> User:
    user = db.query(User).filter(User.id == payload.sub).first()
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    if not user.is_active:
        raise HTTPException(status_code=400, detail="Inactive user")
    return user

def require_admin(current_user: User = Depends(get_current_user)) -> User:
    if not current_user.is_admin:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Admin privileges required"
        )
    return current_user

# Type aliases for clean route signatures
CurrentUser = Annotated[User, Depends(get_current_user)]
AdminUser = Annotated[User, Depends(require_admin)]

@app.get("/me")
async def get_profile(user: CurrentUser):
    return user

@app.get("/admin/users")
async def list_all_users(admin: AdminUser, db: DBSession):
