def require_scope(*required_scopes: str):
    """Returns a dependency that checks for specific OAuth2 scopes."""
    def check_scopes(payload: TokenPayload = Depends(get_token_payload)) -> TokenPayload:
        for scope in required_scopes:
            if scope not in payload.scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Missing required scope: {scope}"
                )
        return payload
    return check_scopes

