class RateLimiter:
    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self._counters: dict = {}

    async def __call__(self, request: Request) -> None:
        client_ip = request.client.host
        current = self._counters.get(client_ip, 0)
        if current >= self.max_requests:
            raise HTTPException(
                status_code=429,
                detail=f"Rate limit exceeded: {self.max_requests} requests per {self.window_seconds}s"
            )
        self._counters[client_ip] = current + 1

# Create instances with different limits for different route groups
